    pub fn load_and_run(&mut self,program: Vec<u8>){
        self.load(program);
        self.program_counter=0x0000;
        self.run();
    }

    pub fn load(&mut self,program: Vec<u8>){
        for i in 0 ..(program.len() as u16){
            self.mem_write(0x0000 + i,program[i as usize]);
        }
    }

    pub fn reset(&mut self){
        self.register_a=0;
        self.register_x=0;
        self.register_y=0;
        self.stack_pointer=STACK_RESET;
        self.status=CpuFlags::from_bits_truncate(0b100100);

        self.program_counter=self.mem_read_u16(0xFFFC);
    }
    pub fn run(&mut self){
        self.run_with_callback(|_|{});
    }

    fn interrupt(&mut self,interrupt: interrupt::Interrupt){
        self.stack_push_u16(self.program_counter);
        let mut flag=self.status.clone();
        flag.set(CpuFlags::BREAK,interrupt.b_flag_mask & 0b010000==1);
        flag.set(CpuFlags::BREAK2,interrupt.b_flag_mask & 0b100000==1);

        self.stack_push(flag.bits);
        self.status.insert(CpuFlags::INTERRUPT_DISABLE);

        self.bus.tick(interrupt.cpu_cycles);
        self.program_counter=self.mem_read_u16(interrupt.vector_addr);
    }

    pub fn run_with_callback<F>(&mut self,mut callback: F)
        where 
            F:FnMut(&mut CPU),
    {
        let ref opcodes: HashMap<u8, &'static opcodes::OpCode> = *opcodes::OPCODES_MAP;

        loop {
            if let Some(_nmi) = self.bus.poll_nmi_status(){
                self.interrupt(interrupt::NMI);
            }
            callback(self);
            let code = self.mem_read(self.program_counter);
            self.program_counter = self.program_counter.wrapping_add(1);
            let program_counter_state = self.program_counter;

            let opcode = opcodes.get(&code).expect(&format!("OpCode {:x} is not recognized", code));

            match code {
                // ADC
                0x69 | 0x65 | 0x75 | 0x6d | 0x7d | 0x79 | 0x61 | 0x71 =>{
                    self.adc(&opcode.mode);
                }

                // AND
                0x29 | 0x25 | 0x35 | 0x2d | 0x3d | 0x39 | 0x21 | 0x31 =>{
                    self.and(&opcode.mode);
                }

                // ASL
                0x0a => self.asl_accumulator(),

                0x06 | 0x16 | 0x0e | 0x1e =>{
                    self.asl(&opcode.mode);
                }

                // BCC
                0x90 => self.bcc(),


                // BCS
                0xb0 => self.bcs(),


                // BEQ
                0xf0 => self.beq(),


                // BIT
                0x24 | 0x2c =>{
                    self.bit(&opcode.mode);
                }

                // BMI
                0x30 => self.bmi(),


                // BNE
                0xd0 => self.bne(),

                // BPL
                0x10 => self.bpl(),


                // BVC
                0x50 => self.bvc(),

                // BVS
                0x70 => self.bvs(),

                // CLC
                0x18 => self.clc(),

                // CLD
                0xd8 => self.cld(),

                // CLI
                0x58 => self.cli(),

                // CLV
                0xb8 => self.clv(),

                // CMP
                0xc9 | 0xc5 | 0xd5 | 0xcd | 0xdd | 0xd9 | 0xc1 | 0xd1 =>{
                    self.cmp(&opcode.mode);
                }

                // AXS/SBX (unofficial)
                0xcb => self.axs(&opcode.mode),

                // CPX
                0xe0 | 0xe4 | 0xec =>{
                    self.cpx(&opcode.mode);
                }

                // CPY
                0xc0 | 0xc4 | 0xcc =>{
                    self.cpy(&opcode.mode);
                }

                // DEC
                0xc6 | 0xd6 | 0xce | 0xde =>{
                    self.dec(&opcode.mode);
                }

                // DEX
                0xca => self.dex(),

                // DEY
                0x88 => self.dey(),

                // EOR
                0x49 | 0x45 | 0x55 | 0x4d | 0x5d | 0x59 | 0x41 | 0x51 =>{
                    self.eor(&opcode.mode);
                }

                // INC
                0xe6 | 0xf6 | 0xee | 0xfe =>{
                    self.inc(&opcode.mode);
                }

                // INX
                0xe8 => self.inx(),

                // INY
                0xc8 => self.iny(),

                // JMP
                // Absolute
                0x4c =>{
                    let mem_address=self.mem_read_u16(self.program_counter);
                    self.program_counter=mem_address;
                }
                // Indirect
                0x6c =>{
                    let mem_address=self.mem_read_u16(self.program_counter);
                    let indirect_ref= if mem_address & 0x00FF == 0x00FF{
                        let lo=self.mem_read(mem_address);
                        let hi=self.mem_read(mem_address & 0xFF00);
                        (hi as u16) << 8 | (lo as u16)
                    }else{
                        self.mem_read_u16(mem_address)
                    };

                    self.program_counter=indirect_ref;
                }

                // JSR
                0x20 => self.jsr(),

                // LDA
                0xa9 | 0xa5 | 0xb5 | 0xad | 0xbd | 0xb9 | 0xa1 | 0xb1 =>{
                    self.lda(&opcode.mode);
                }

                // LDX
                0xa2 | 0xa6 | 0xb6 | 0xae | 0xbe =>{
                    self.ldx(&opcode.mode);
                }

                // LDY
                0xa0 | 0xa4 | 0xb4 | 0xac | 0xbc =>{
                    self.ldy(&opcode.mode);
                }

                // LSR
                0x4a => self.lsr_accumulator(),

                0x46 | 0x56 | 0x4e | 0x5e =>{
                    self.lsr(&opcode.mode);
                }

                // NOP
                0xea => {

                }

                // ORA
                0x09 | 0x05 | 0x15 | 0x0d | 0x1d | 0x19 | 0x01 | 0x11 =>{
                    self.ora(&opcode.mode);
                }

                // PHA
                0x48 => self.pha(),

                // PHP
                0x08 => self.php(),

                // PLA
                0x68 => self.pla(),

                // PLP
                0x28 => self.plp(),

                // ROL
                0x2a => self.rol_accumulator(),

                0x26 | 0x36 | 0x2e | 0x3e =>{
                    self.rol(&opcode.mode);
                }

                // ROR
                0x6a => self.ror_accumulator(),

                0x66 | 0x76 | 0x6e | 0x7e =>{
                    self.ror(&opcode.mode);
                }

                // RTI
                0x40 => self.rti(),

                // RTS
                0x60 => self.rts(),

                // SBC
                0xe9 | 0xe5 | 0xf5 | 0xed | 0xfd | 0xf9 | 0xe1 | 0xf1 =>{
                    self.sbc(&opcode.mode);
                }

                // SEC
                0x38 => self.sec(),

                // SED
                0xf8 => self.sed(),

                // SEI
                0x78 => self.sei(),

                // STA 
                0x85 | 0x95 | 0x8d | 0x9d | 0x99 | 0x81 | 0x91 => {
                    self.sta(&opcode.mode);
                }

                // STX
                0x86 | 0x96 | 0x8e =>{
                    self.stx(&opcode.mode);
                }

                // STY
                0x84 | 0x94 | 0x8c =>{
                    self.sty(&opcode.mode);
                }

                // TAX
                0xaa => self.tax(),

                // TAY
                0xa8 => self.tay(),

                // TSX
                0xba => self.tsx(),

                // TXA
                0x8a => self.txa(),

                // TXS
                0x9a => self.txs(),

                // TYA
                0x98 => self.tya(),

                0x00 => return,
                _ => todo!(),
            }

            self.bus.tick(opcode.cycles);

            if program_counter_state == self.program_counter {
                self.program_counter = self
                    .program_counter
                    .wrapping_add((opcode.len - 1) as u16);
            }
        }
    }
}

#[cfg(test)]
mod test {
    use super::*;
    use crate::cartridge::test;
    use crate::ppu::NesPPU;
    use crate::joypad::Joypad;
    use crate::apu::NesAPU;

    #[test]
    fn test_0xa9_lda_immediate_load_data() {
        let bus=Bus::new(test::test_rom(vec![]), |_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);

        cpu.load_and_run(vec![0xa9, 0x05, 0x00]);

        assert_eq!(cpu.register_a, 5);
        assert!(cpu.status.bits() & 0b0000_0010 == 0b00);
        assert!(cpu.status.bits() & 0b1000_0000 == 0);
    }

    #[test]
    fn test_0xaa_tax_move_a_to_x() {
        let bus=Bus::new(test::test_rom(vec![]), |_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);
        cpu.register_a = 10;

        cpu.load_and_run(vec![0xaa, 0x00]);

        assert_eq!(cpu.register_x, 10)
    }

    #[test]
    fn test_5_ops_working_together() {
        let bus=Bus::new(test::test_rom(vec![]),|_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);

        cpu.load_and_run(vec![0xa9, 0xc0, 0xaa, 0xe8, 0x00]);

        assert_eq!(cpu.register_x, 0xc1)
    }

    #[test]
    fn test_inx_overflow() {
        let bus=Bus::new(test::test_rom(vec![]),|_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);
        cpu.register_x = 0xff;

        cpu.load_and_run(vec![0xe8, 0xe8, 0x00]);

        assert_eq!(cpu.register_x, 1)
    }

    #[test]
    fn test_program_counter_wraps_on_opcode_fetch() {
        let mut program = vec![0; 0x8000];
        program[0x7fff] = 0x00;
        let bus=Bus::new(test::test_rom(program),|_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);
        cpu.program_counter = 0xffff;

        cpu.run();

        assert_eq!(cpu.program_counter, 0x0000);
    }

    #[test]
    fn test_0xcb_axs_updates_x_and_carry() {
        let bus=Bus::new(test::test_rom(vec![]),|_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);

        cpu.load_and_run(vec![
            0xa9, 0x0f, // LDA #$0f
            0xa2, 0x0a, // LDX #$0a
            0xcb, 0x08, // AXS #$08 => X = (0x0f & 0x0a) - 0x08 = 0x02
            0x00,
        ]);

        assert_eq!(cpu.register_x, 0x02);
        assert!(cpu.status.contains(CpuFlags::CARRY));
        assert!(!cpu.status.contains(CpuFlags::ZERO));
        assert!(!cpu.status.contains(CpuFlags::NEGATIV));
    }

    #[test]
    fn test_0xcb_axs_wraps_and_clears_carry() {
        let bus=Bus::new(test::test_rom(vec![]),|_ppu,_apu,_joypad|{});
        let mut cpu = CPU::new(bus);

        cpu.load_and_run(vec![
            0xa9, 0x03, // LDA #$03
            0xa2, 0x07, // LDX #$07
            0xcb, 0x05, // AXS #$05 => X = (0x03 & 0x07) - 0x05 = 0xfe
            0x00,
        ]);

        assert_eq!(cpu.register_x, 0xfe);
        assert!(!cpu.status.contains(CpuFlags::CARRY));
        assert!(!cpu.status.contains(CpuFlags::ZERO));
        assert!(cpu.status.contains(CpuFlags::NEGATIV));

