    fn axs(&mut self, mode: &AddressingMode) {
        let addr = self.get_operand_address(mode);
        let value = self.mem_read(addr);
        let anded = self.register_a & self.register_x;
        self.status.set(CpuFlags::CARRY, anded >= value);
